//Account class implementing interface AccountService
public class SavingsAccount implements AccountService {
    private double balance;
  
    public SavingsAccount(double balance) {
        this.balance = balance;
    }
  
    @Override
    public boolean debit(double amount) {
        if (amount > balance){
            return false;
        } else {
            balance -= amount;
            return true;
        }
    }
  
    @Override
    public void credit(double amount) {
        balance += amount;
    }
  
    @Override
    public double getBalance() {
        return balance;
    }
}
  
//AccountService interface
public interface AccountService {
     boolean debit(double amount);
     void credit(double amount);
     double getBalance();
}
  
//Bank class handling transactions
public class Bank {
    private List<Account> accounts;  //Assuming each bank has many accounts. So, list of accounts is maintained here.

    public Bank() {
        this.accounts = new ArrayList<>();
    }

    public void addAccount(Account account) {
        accounts.add(account);
    }
  
    //Deposit to an Account
    public boolean depositToAccount(int accNum, double amount){
        if (accNum >= 0 && accNum < accounts.size()) {
            accounts.get(accNum).credit(amount);
            return true;
        } else {
            return false; //Invalid account number
        }
    }
  
    //Withdraw from an Account
    public boolean withdrawFromAccount(int accNum, double amount) {
        if (accNum >= 0 && accNum < accounts.size()) {
            return accounts.get(accNum).debit(amount);  //If sufficient balance available then true otherwise false is returned.
        } else {
            return false; //Invalid account number
        }
    }
  
    public double checkBalanceOfAccount(int accNum) {
        if (accNum >= 0 && accNum < accounts.size()) {
            return accounts.get(accNum).getBalance();
        } else {
            throw new IllegalArgumentException("Invalid account number");  //As per the requirement, returning an exception is more suitable than simply returning false or negative value indicating invalid input
        }
    }
}